import{_ as a,o as r,c as i,a2 as t}from"./chunks/framework.C7GIOALF.js";const m=JSON.parse('{"title":"Horde","description":"","frontmatter":{},"headers":[],"relativePath":"formats/horde/index.md","filePath":"formats/horde/index.md","lastUpdated":1782025909000}'),o={name:"formats/horde/index.md"};function l(s,e,n,d,c,h){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="horde" tabindex="-1">Horde <a class="header-anchor" href="#horde" aria-label="Permalink to &quot;Horde&quot;">​</a></h1><p>Horde formats are cooperative Magic variants where one to four players fight an automated enemy deck. The enemy deck usually has no hand, no life total, and no pilot; damage mills its library, and the players win by surviving until the Horde is empty and its board is cleared.</p><h2 id="base-play-pattern" tabindex="-1">Base Play Pattern <a class="header-anchor" href="#base-play-pattern" aria-label="Permalink to &quot;Base Play Pattern&quot;">​</a></h2><ul><li>Players take several setup turns before the Horde begins.</li><li>The Horde reveals cards from the top of its library until the wave ends.</li><li>The Horde has effectively infinite mana for casting and activation costs.</li><li>Horde creatures usually have haste and attack each turn if able.</li><li>Damage dealt to the Horde mills that many cards from the Horde library.</li><li>Players win when the Horde library and battlefield are empty.</li><li>The Horde wins when the players lose by life total, poison, draw failure, or another agreed loss condition.</li></ul><h2 id="source-references" tabindex="-1">Source References <a class="header-anchor" href="#source-references" aria-label="Permalink to &quot;Source References&quot;">​</a></h2><ul><li><a href="./sources/hordemagic-com.html">HordeMagic.com notes</a> Original URL: <a href="https://hordemagic.com/" target="_blank" rel="noreferrer">https://hordemagic.com/</a></li><li><a href="./sources/original-horde-magic-quiet-speculation.html">Original Horde Magic article by Peter Knudson</a> Original URL: <a href="https://www.quietspeculation.com/2011/09/horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2011/09/horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions/</a></li><li><a href="./sources/horde-magic-open-source-quiet-speculation.html">Horde Magic: An Open Source Project</a> Original URL: <a href="https://www.quietspeculation.com/2011/10/horde-magic-an-open-source-project/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2011/10/horde-magic-an-open-source-project/</a></li><li><a href="./sources/horde-magic-wiki.html">Horde Magic wiki rules</a> Original URL: <a href="https://mtg.fandom.com/wiki/Horde_Magic#Rules_for_The_Horde" target="_blank" rel="noreferrer">https://mtg.fandom.com/wiki/Horde_Magic#Rules_for_The_Horde</a></li><li><a href="./sources/horde-raid-quiet-speculation.html">Horde Magic 2.0: The Raid</a> Original URL: <a href="https://www.quietspeculation.com/2013/02/horde-magic-2-0-introducing-the-raid/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2013/02/horde-magic-2-0-introducing-the-raid/</a></li></ul><h2 id="variants-to-track" tabindex="-1">Variants To Track <a class="header-anchor" href="#variants-to-track" aria-label="Permalink to &quot;Variants To Track&quot;">​</a></h2><ul><li>Classic Zombie Horde.</li><li>HordeMagic.com EDH-style variant.</li><li>Raid-style staged Horde decks.</li><li>Companion-deck or class-deck versions where the players use prebuilt survivor decks.</li></ul><h2 id="boxed-set-notes" tabindex="-1">Boxed-Set Notes <a class="header-anchor" href="#boxed-set-notes" aria-label="Permalink to &quot;Boxed-Set Notes&quot;">​</a></h2><p>A Horde box should probably include:</p><ul><li>One Horde deck.</li><li>Tokens and counters used by that Horde.</li><li>A difficulty chart by player count.</li><li>A ban/watch list for player decks.</li><li>A quick reference for Horde targeting and decision rules.</li></ul>',11)])])}const p=a(o,[["render",l]]);export{m as __pageData,p as default};
